const fs = require('fs');
const PATH = '/data/state/pending-callbacks.json';

const body = $input.first().json.body;
if (!body || !body.callback_query) {
  throw new Error('Missing callback_query in webhook payload — not a Telegram callback POST?');
}

const cb = body.callback_query;
const rawData = cb.data || '';

let action = 'unknown';
let suffix = '';
let competitionIdLegacy = '';

// Format detection priority:
// 1. Legacy URL-encoded "action=<verb>&competition_id=<slug>" — when "=" in rawData.
// 2. Compact "<j|s>:<shortid|slug>" — when ":" at position 1.
if (rawData.includes('=')) {
  const params = Object.fromEntries(
    rawData
      .split('&')
      .filter(Boolean)
      .map((pair) => {
        const [key, ...valueParts] = pair.split('=');
        return [
          decodeURIComponent(key),
          decodeURIComponent(valueParts.join('=')),
        ];
      })
  );
  action = params.action || 'unknown';
  competitionIdLegacy = params.competition_id || '';
} else {
  const colonIdx = rawData.indexOf(':');
  if (colonIdx === 1) {
    const prefix = rawData[0];
    suffix = rawData.slice(2);
    if (prefix === 'j') action = 'join';
    else if (prefix === 's') action = 'skip';
  }
}

// Stash lookup. Returns the resolved entry on hit, null on miss.
let entry = null;
let stashError = null;
if (suffix) {
  try {
    const list = JSON.parse(fs.readFileSync(PATH, 'utf8'));
    if (Array.isArray(list)) {
      entry = list.find((e) => e.shortid === suffix) || null;
    }
  } catch (err) {
    if (err.code !== 'ENOENT') {
      // Don't swallow — surface storage failure via the Error Handler so
      // a corrupt or unreadable stash file does not silently turn live
      // callbacks into half-broken executions. ENOENT stays silent (a
      // fresh install with no stash file yet is normal).
      stashError = err.message;
    }
  }

  const isHexHash = /^[0-9a-f]{6,16}$/.test(suffix);
  if (!entry && !isHexHash) {
    // Phase A slug fallback: suffix is not a hex hash, treat it as a
    // direct slug for the simulated curl test harness.
    entry = { competition_id: suffix };
  } else if (!entry && isHexHash) {
    // Hex-hash suffix but stash miss: the entry has been pruned (>30d),
    // never written, or the file became unreadable above. Reset action
    // to 'unknown' rather than routing a click to join/skip with empty
    // context — the Switch fallback then handles it loudly via Answer
    // Unknown, surfacing the issue instead of silently producing a
    // half-broken execution downstream. Caught by Copilot review on PR #69.
    action = 'unknown';
  }
}

if (stashError) {
  throw new Error(`Pending callbacks stash read failed: ${stashError}`);
}

const competition_id = entry?.competition_id || competitionIdLegacy;

return [{
  json: {
    action,
    competition_id,
    competition_url:   entry?.competition_url   || '',
    competition_name:  entry?.competition_name  || '',
    email_id:          entry?.email_id          || '',
    chat_id:           cb.message?.chat?.id     ?? entry?.chat_id ?? '',
    message_id:        cb.message?.message_id   ?? entry?.message_id ?? null,
    callback_query_id: cb.id,
    from_user_id:      cb.from?.id,
    from_first_name:   cb.from?.first_name,
    raw_data:          rawData,
    stash_hit:         !!entry?.shortid,
  },
}];
